import json
import os
from pathlib import Path
from unittest.mock import MagicMock
import pytest

# ---- Deterministic mock LLM ----
class MockLLM:
    '''Deterministic 'LLM' for tests. Maps prompt -> canned response.
    Falls back to a suffix match on the prompt if exact not found.'''
    def __init__(self, canned: dict[str, str]):
        self.canned = canned
        self.calls: list[dict] = []

    def complete(self, prompt: str, **kwargs) -> str:
        self.calls.append({'prompt': prompt, **kwargs})
        if prompt in self.canned:
            return self.canned[prompt]
        for key, resp in self.canned.items():
            if prompt.endswith(key) or key in prompt:
                return resp
        raise ValueError(f'No canned response for prompt (first 80 chars): {prompt[:80]!r}')

@pytest.fixture
def mock_llm():
    return MockLLM({
        'What is 2+2?': '4',
        'Summarize: The data layer was rebuilt.': 'The data layer was rebuilt.',
    })

