    name = request.node.name + '.json'
    cassette = CASSETTE_DIR / name
    recording = os.getenv('RECORD') == '1' or not cassette.exists()
    data = {} if recording else json.loads(cassette.read_text())

    def wrap(fn):
        def inner(messages, **kw):
            key = json.dumps(messages, sort_keys=True)
            if recording:
                res = fn(messages, **kw)
