// RAG with LangChain.js + Supabase pgvector
// pnpm add @langchain/community @langchain/openai @supabase/supabase-js
// Env: OPENAI_API_KEY, SUPABASE_URL, SUPABASE_SERVICE_KEY

import { OpenAIEmbeddings, ChatOpenAI } from '@langchain/openai';
import { SupabaseVectorStore } from '@langchain/community/vectorstores/supabase';
import { createClient } from '@supabase/supabase-js';
import { ChatPromptTemplate } from '@langchain/core/prompts';
import { RunnableSequence, RunnablePassthrough } from '@langchain/core/runnables';
import { StringOutputParser } from '@langchain/core/output_parsers';

// Supabase SQL (run once):
//   CREATE EXTENSION IF NOT EXISTS vector;
//   CREATE TABLE documents ( id bigserial PRIMARY KEY, content text, metadata jsonb, embedding vector(1536) );
//   CREATE FUNCTION match_documents (query_embedding vector(1536), match_count int DEFAULT 10) ... (standard template)

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_KEY!);
const embeddings = new OpenAIEmbeddings({ model: 'text-embedding-3-small' });
const store = new SupabaseVectorStore(embeddings, { client: supabase, tableName: 'documents' });

// --- Ingest ---
export async function ingest(docs: { pageContent: string; metadata: Record<string, unknown> }[]) {
  await store.addDocuments(docs);
  console.log(`Ingested ${docs.length} documents`);
}

// --- Retrieve + generate with citations ---
const promptTmpl = ChatPromptTemplate.fromTemplate(`You are an expert assistant. Answer using ONLY the context below. Cite sources like [1], [2].

Context:
{context}

Question: {question}

Answer:`);

const llm = new ChatOpenAI({ model: 'gpt-4o-mini', temperature: 0.1 });

export async function ask(question: string, k: number = 4): Promise<{ answer: string; sources: { id: unknown; snippet: string }[] }> {
  const docs = await store.similaritySearch(question, k);
  const context = docs
    .map((d, i) => `[${i + 1}] ${d.pageContent}`)
    .join('\n\n');

  const chain = RunnableSequence.from([
    { context: () => context, question: new RunnablePassthrough() },
    promptTmpl,
    llm,
    new StringOutputParser(),
  ]);

  const answer = await chain.invoke(question);
  const sources = docs.map((d, i) => ({ id: d.metadata.id ?? i, snippet: d.pageContent.slice(0, 160) }));
  return { answer, sources };
}

// --- Demo ---
if (require.main === module) {
  (async () => {
    await ingest([
      { pageContent: 'OSS AI Hub curates 1,351 open-source AI tools with live GitHub stars.', metadata: { id: 'doc1', source: 'about' } },
      { pageContent: 'Stars refresh nightly via a public GitHub Actions cron.', metadata: { id: 'doc2', source: 'trust' } },
    ]);
    const res = await ask('How does OSS AI Hub keep star counts accurate?');
    console.log('Answer:\n', res.answer);
    console.log('Sources:', res.sources);
  })();
}

