import json
import anthropic

client = anthropic.Anthropic()

TOOLS = [
    {
        'name': 'get_weather',
        'description': 'Get the current weather in a city',
        'input_schema': {
            'type': 'object',
            'properties': {
                'city': {'type': 'string', 'description': 'City name'},
                'unit': {'type': 'string', 'enum': ['c', 'f'], 'default': 'c'},
            },
            'required': ['city'],
        },
    },
    {
        'name': 'search_docs',
        'description': 'Search internal docs for relevant snippets',
        'input_schema': {
            'type': 'object',
            'properties': {'query': {'type': 'string'}},
            'required': ['query'],
        },
    },
]

def execute_tool(name: str, args: dict) -> str:
    # Replace with real implementations
    if name == 'get_weather':
        return json.dumps({'city': args['city'], 'tempC': 18, 'condition': 'partly cloudy'})
    if name == 'search_docs':
        return json.dumps({'results': [{'title': 'Quickstart', 'snippet': 'Install with pip install anthropic...'}]})
    return json.dumps({'error': f'unknown tool: {name}'})

def run_with_tools(user_input: str, model: str = 'claude-3-5-sonnet-latest'):
    messages = [{'role': 'user', 'content': user_input}]

    while True:
        with client.messages.stream(
            model=model,
            max_tokens=1024,
            system='You are a concise assistant. Use tools when relevant.',
            tools=TOOLS,
            messages=messages,
        ) as stream:
            # Stream text deltas as they come
            for text in stream.text_stream:
                print(text, end='', flush=True)
            final = stream.get_final_message()

        print()  # newline after stream ends

        if final.stop_reason != 'tool_use':
            return final  # done — final answer is complete

        # Extract tool uses, execute, append results, loop
        tool_uses = [b for b in final.content if b.type == 'tool_use']
        messages.append({'role': 'assistant', 'content': final.content})

        tool_results = []
        for tu in tool_uses:
            print(f'\n[tool: {tu.name}({json.dumps(tu.input)})]')
            result = execute_tool(tu.name, tu.input)
            tool_results.append({'type': 'tool_result', 'tool_use_id': tu.id, 'content': result})

        messages.append({'role': 'user', 'content': tool_results})
        print('[continuing...]\n')

if __name__ == '__main__':
    run_with_tools("What's the weather in Paris today? Also, check our docs for install instructions.")
